// 【空间告急清理】剩余空间小于硬盘总容量10%时，无论进度状态，删除上传速度最低（速度相同时删体积最大）的种子
(maindata, torrent) => {
  const categoryList = ["不删", "keep", "养老"];
  const { category } = torrent.originProp;

  // 1. 最基础的过滤：保留特定分类（已取消进度必须100%的限制）
  if (categoryList.indexOf(category) !== -1) return false;

  // 2. 获取 qBittorrent 服务器真实的剩余空间（freeSpace）和总容量（totalSpace）
  // 注意：并非所有下载器 API 都会准确返回 server_state 对象或者总容量信息，qbittorrent 通常包含
  const serverState = maindata.serverState || maindata.server_state || {};

  const freeSpace = serverState.free_space_on_disk !== undefined 
    ? serverState.free_space_on_disk 
    : maindata.freeSpaceOnDisk;

  // QBT API 并非默认直接暴露总空间，这里用所有下载目录所在盘符的总空间来替代，
  // 我们通过 qBittorrent 状态中获取的总物理硬盘大小。
  // 如果 API 没返回总容量，为了安全起见，我们只能假设一个默认触发值(比如90G)防止误删。
  const totalSpace = serverState.total_space_on_disk !== undefined 
    ? serverState.total_space_on_disk 
    : null;

  if (!freeSpace) return false;

  // 3. 核心计算：检查剩余空间是否小于总容量的 10%
  // 如果无法获取到 totalSpace (比如使用了古老版本的下载器)，为了防灾保险起见，默认退回到当剩余空间不到 100GB 时触发。
  let isSpaceLow = false;

  if (totalSpace) {
      // 真实硬盘大小的 10%
      const threshold = totalSpace * 0.1;
      isSpaceLow = (freeSpace < threshold);
  } else {
      // 备用触发方案 (Fallback)
      isSpaceLow = (freeSpace < util.calSize(100, "GiB"));
  }

  // 如果空间很安全，直接跳过不删
  if (!isSpaceLow) {
    return false; 
  }

  // 4. 空间不足！开始在所有种子中“选妃”，挑出一个速度最低的
  const allTorrents = maindata.torrents || {};
  let targetHash = null;
  let minSpeed = Infinity;
  let maxSize = -1;

  // 使用 for...in 遍历避免 Vertex OOM 爆内存
  for (const hash in allTorrents) {
    const t = allTorrents[hash];

    // 取出的属性可能为空，给个默认值
    const tCategory = t.category || "";

    // 只挑选不在保留分类里的种子做比较，不关心它是否下载完毕
    if (categoryList.indexOf(tCategory) !== -1) {
      continue;
    }

    const speed = t.upspeed || 0;
    const size = t.size || 0;

    // 核心规则：上传速度更低，或者速度同样低但体积更大
    if (speed < minSpeed || (speed === minSpeed && size > maxSize)) {
      minSpeed = speed;
      maxSize = size;
      targetHash = hash;
    }
  }

  // 5. 判断当前被 Vertex 评估的这颗种子，是不是刚刚挑出来的“天选之子”
  if (targetHash && torrent.hash && torrent.hash.toLowerCase() === targetHash.toLowerCase()) {
    return true; // 是的话就果断开绿灯，执行删除！
  }

  return false;
};
